def eval_expr(s):
    s = s.replace(' ', '')
    nums = []
    ops = []
    i = 0
    while i < len(s):
        if s[i].isdigit():
            j = i
            while j < len(s) and s[j].isdigit():
                j += 1
            nums.append(int(s[i:j]))
            i = j
        else:
            ops.append(s[i])
            i += 1
    new_nums = [nums[0]]
    new_ops = []
    for k, op in enumerate(ops):
        if op == '*':
            new_nums[-1] = new_nums[-1] * nums[k+1]
        elif op == '/':
            new_nums[-1] = int(new_nums[-1] / nums[k+1])
        else:
            new_nums.append(nums[k+1])
            new_ops.append(op)
    result = new_nums[0]
    for k, op in enumerate(new_ops):
        if op == '+':
            result += new_nums[k+1]
        else:
            result -= new_nums[k+1]
    return result

