def bfs_shortest(adj, start, end):
    if start == end:
        return 0
    from collections import deque
    visited = {start}
    q = deque([(start, 0)])
    while q:
        node, dist = q.popleft()
        for nb in adj.get(node, []):
            if nb == end:
                return dist + 1
            if nb not in visited:
                visited.add(nb)
                q.append((nb, dist + 1))
    return -1

