class Queue:
    def __init__(self):
        self._in = []
        self._out = []
    def enqueue(self, val):
        self._in.append(val)
    def _transfer(self):
        if not self._out:
            while self._in:
                self._out.append(self._in.pop())
    def dequeue(self):
        self._transfer()
        if not self._out:
            raise IndexError('dequeue from empty queue')
        return self._out.pop()
    def peek(self):
        self._transfer()
        if not self._out:
            raise IndexError('peek from empty queue')
        return self._out[-1]
    def is_empty(self):
        return len(self._in) + len(self._out) == 0
    def size(self):
        return len(self._in) + len(self._out)

