class MinStack:
    def __init__(self):
        self._stack = []
        self._mins = []
    def push(self, val):
        self._stack.append(val)
        if not self._mins or val <= self._mins[-1]:
            self._mins.append(val)
    def pop(self):
        if not self._stack:
            raise IndexError('pop from empty stack')
        val = self._stack.pop()
        if val == self._mins[-1]:
            self._mins.pop()
        return val
    def top(self):
        if not self._stack:
            raise IndexError('top from empty stack')
        return self._stack[-1]
    def get_min(self):
        if not self._mins:
            raise IndexError('min from empty stack')
        return self._mins[-1]

