class BST:
    class Node:
        def __init__(self, val):
            self.val = val
            self.left = None
            self.right = None
    def __init__(self):
        self.root = None
    def insert(self, val):
        def _insert(node, val):
            if not node:
                return self.Node(val)
            if val < node.val:
                node.left = _insert(node.left, val)
            elif val > node.val:
                node.right = _insert(node.right, val)
            return node
        self.root = _insert(self.root, val)
    def search(self, val):
        def _search(node, val):
            if not node:
                return False
            if val == node.val:
                return True
            if val < node.val:
                return _search(node.left, val)
            return _search(node.right, val)
        return _search(self.root, val)
    def inorder(self):
        result = []
        def _inorder(node):
            if node:
                _inorder(node.left)
                result.append(node.val)
                _inorder(node.right)
        _inorder(self.root)
        return result

