class KVStore:
    def __init__(self):
        self.store = {}
    def set(self, key, value, ttl, current_time):
        self.store[key] = (value, current_time + ttl)
    def get(self, key, current_time):
        if key not in self.store:
            return None
        value, expiry = self.store[key]
        if current_time >= expiry:
            del self.store[key]
            return None
        return value

