class PeekIterator:
    def __init__(self, iterator):
        self._iter = iterator
        self._peeked = None
        self._has_peeked = False
        self._exhausted = False
    def peek(self):
        if not self._has_peeked:
            try:
                self._peeked = next(self._iter)
                self._has_peeked = True
            except StopIteration:
                self._exhausted = True
                raise
        return self._peeked
    def next(self):
        if self._has_peeked:
            self._has_peeked = False
            return self._peeked
        return next(self._iter)
    def has_next(self):
        if self._has_peeked:
            return True
        if self._exhausted:
            return False
        try:
            self._peeked = next(self._iter)
            self._has_peeked = True
            return True
        except StopIteration:
            self._exhausted = True
            return False

