def simple_match(pattern, text):
    m, n = len(pattern), len(text)
    dp = [[False]*(n+1) for _ in range(m+1)]
    dp[0][0] = True
    for i in range(1, m+1):
        if pattern[i-1] == '*':
            dp[i][0] = dp[i-1][0]
    for i in range(1, m+1):
        for j in range(1, n+1):
            if pattern[i-1] == '*':
                dp[i][j] = dp[i-1][j] or dp[i][j-1]
            elif pattern[i-1] == '?' or pattern[i-1] == text[j-1]:
                dp[i][j] = dp[i-1][j-1]
    return dp[m][n]

assert simple_match('he*o', 'hello') == True
assert simple_match('he?lo', 'hello') == True
assert simple_match('*', 'anything') == True
assert simple_match('he*o', 'help') == False
assert simple_match('', '') == True
assert simple_match('?', '') == False
assert simple_match('a*b', 'ab') == True
assert simple_match('a*b', 'aXXXb') == True
