class Node:
    def __init__(self, val, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def serialize(root):
    tokens = []
    def helper(node):
        if node is None:
            tokens.append('#')
            return
        tokens.append(str(node.val))
        helper(node.left)
        helper(node.right)
    helper(root)
    return ','.join(tokens)

def deserialize(data):
    tokens = iter(data.split(','))
    def helper():
        val = next(tokens)
        if val == '#':
            return None
        node = Node(int(val))
        node.left = helper()
        node.right = helper()
        return node
    return helper()

def trees_equal(a, b):
    if a is None and b is None:
        return True
    if a is None or b is None:
        return False
    return a.val == b.val and trees_equal(a.left, b.left) and trees_equal(a.right, b.right)

root = Node(1, Node(2), Node(3, Node(4), Node(5)))
assert trees_equal(deserialize(serialize(root)), root)
assert deserialize(serialize(None)) is None
single = Node(42)
assert trees_equal(deserialize(serialize(single)), single)
left_only = Node(1, Node(2, Node(3)))
assert trees_equal(deserialize(serialize(left_only)), left_only)
