class IntervalSet:
    def __init__(self):
        self.intervals = []
    def add(self, lo, hi):
        new = []
        inserted = False
        for s, e in self.intervals:
            if e < lo:
                new.append([s, e])
            elif s > hi:
                if not inserted:
                    new.append([lo, hi])
                    inserted = True
                new.append([s, e])
            else:
                lo = min(lo, s)
                hi = max(hi, e)
        if not inserted:
            new.append([lo, hi])
        self.intervals = new
    def query(self, x):
        for s, e in self.intervals:
            if s <= x <= e:
                return True
        return False
    def get_intervals(self):
        return [iv[:] for iv in self.intervals]

s = IntervalSet()
s.add(1, 3)
s.add(5, 7)
assert s.get_intervals() == [[1,3],[5,7]]
assert s.query(2) == True
assert s.query(4) == False
s.add(2, 6)
assert s.get_intervals() == [[1,7]]
assert s.query(4) == True
assert IntervalSet().get_intervals() == []
